import json
from typing import Union


def flatten_ec2_metadata(data: Union[dict, str], max_depth: int = 20) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters
    ----------
    data : dict or str
        The EC2 metadata as a pre-parsed dict or a raw JSON string.
        If a string is provided, json.loads() is called explicitly before processing.
    max_depth : int, optional
        Maximum nesting depth allowed (default: 20). The root dict is processed at
        depth=0, meaning depth=0 means 'processing the root dict and its direct children',
        depth=1 means the second level of nesting, and so on. A ValueError is raised
        when depth reaches max_depth (i.e., depth >= max_depth), so a maximum of exactly
        20 levels of nesting are permitted.

    Returns
    -------
    dict
        A flat dictionary where nested keys are joined with dot-notation
        (e.g., 'network.interfaces.0.mac'). If the root value is not a dict,
        returns {"" : <scalar_value>}.

    Raises
    ------
    ValueError
        If input is None or not a dict or str type.
        If a JSON string cannot be parsed by json.loads().
        If nesting depth reaches max_depth during recursion.

    Examples
    --------
    >>> metadata = {"instance": {"id": "i-1234", "tags": ["web", "prod"]}}
    >>> flatten_ec2_metadata(metadata, max_depth=20)
    {'instance.id': 'i-1234', 'instance.tags.0': 'web', 'instance.tags.1': 'prod'}

    >>> deep = {"a": {"b": {"c": {"d": {"e": {"f": {"g": {"h": {"i": {"j": {"k": {"l": {"m": {"n": {"o": {"p": {"q": {"r": {"s": {"t": "deep"}}}}}}}}}}}}}}}}}}}}}}
    >>> try:
    ...     flatten_ec2_metadata(deep, max_depth=5)
    ... except ValueError as e:
    ...     print("ValueError raised")
    ValueError raised
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError("Input must be a dict or a JSON string, got: {}".format(type(data)))

    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError("Failed to parse JSON string: {}".format(e))

    if not isinstance(data, dict):
        return {"": data}

    def _flatten(obj: dict, prefix: str, depth: int, result: dict) -> None:
        if depth >= max_depth:
            raise ValueError("Maximum nesting depth of {} exceeded".format(max_depth))
        for key, value in obj.items():
            full_key = prefix + "." + key if prefix else key
            if isinstance(value, dict):
                _flatten(value, full_key, depth + 1, result)
            elif isinstance(value, list):
                for i, item in enumerate(value):
                    item_key = full_key + "." + str(i)
                    if isinstance(item, dict):
                        if depth + 1 >= max_depth:
                            raise ValueError("Maximum nesting depth of {} exceeded".format(max_depth))
                        _flatten(item, item_key, depth + 1, result)
                    else:
                        if depth >= max_depth:
                            raise ValueError("Maximum nesting depth of {} exceeded".format(max_depth))
                        result[item_key] = item
            else:
                result[full_key] = value

    result = {}
    _flatten(data, "", 0, result)
    return result
